def {{nama_fungsi}}(arr, target):
    """Binary search. Return index jika ketemu, else -1."""
    lo, hi = 0, len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

def {{nama_fungsi}}(arr):
    """QuickSort, return list baru sorted."""
    if len(arr) <= 1:
        return arr[:]
    pivot = arr[len(arr)//2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return {{nama_fungsi}}(left) + middle + {{nama_fungsi}}(right)

def {{nama_fungsi}}(lists):
    """Merge multiple sorted lists."""
    import heapq
    heap = []
    result = []
    iterators = [iter(lst) for lst in lists]
    for i, it in enumerate(iterators):
        try:
            val = next(it)
            heapq.heappush(heap, (val, i))
        except StopIteration:
            pass
    while heap:
        val, i = heapq.heappop(heap)
        result.append(val)
        try:
            nxt = next(iterators[i])
            heapq.heappush(heap, (nxt, i))
        except StopIteration:
            pass
    return result

def {{nama_fungsi}}(s1, s2):
    """Hitung Levenshtein distance."""
    if len(s1) < len(s2):
        return {{nama_fungsi}}(s2, s1)
    previous = list(range(len(s2) + 1))
    for i, c1 in enumerate(s1, 1):
        current = [i]
        for j, c2 in enumerate(s2, 1):
            ins = previous[j] + 1
            delete = current[j-1] + 1
            sub = previous[j-1] + (c1 != c2)
            current.append(min(ins, delete, sub))
        previous = current
    return previous[-1]

def {{nama_fungsi}}(nums, window_size={{window_size}}):
    """Yield avg untuk setiap sliding window."""
    if window_size <= 0 or window_size > len(nums):
        return
    window_sum = sum(nums[:window_size])
    yield window_sum / window_size
    for i in range(window_size, len(nums)):
        window_sum += nums[i] - nums[i - window_size]
        yield window_sum / window_size

def {{nama_fungsi}}(nums, target):
    """Return indices dua angka yang sum = target, atau None."""
    seen = {}
    for i, n in enumerate(nums):
        need = target - n
        if need in seen:
            return (seen[need], i)
        seen[n] = i
    return None

def {{nama_fungsi}}(weights, values, capacity):
    """0/1 Knapsack. Return max value."""
    n = len(weights)
    dp = [0] * (capacity + 1)
    for i in range(n):
        w = weights[i]
        v = values[i]
        for c in range(capacity, w-1, -1):
            dp[c] = max(dp[c], dp[c-w] + v)
    return dp[capacity]

def {{nama_fungsi}}(a, b):
    """Return panjang LCS."""
    m, n = len(a), len(b)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if a[i-1] == b[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

def {{nama_fungsi}}(graph):
    """graph: dict node -> list neighbors. Return topo order list."""
    from collections import deque, defaultdict
    indeg = defaultdict(int)
    nodes = set(graph.keys())
    for u in graph:
        for v in graph[u]:
            indeg[v] += 1
            nodes.add(v)
    q = deque([n for n in nodes if indeg[n] == 0])
    order = []
    while q:
        u = q.popleft()
        order.append(u)
        for v in graph.get(u, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
    if len(order) != len(nodes):
        raise ValueError("Graph contains cycle")
    return order
